    function seofy_fonts_url() {
		$fonts_url = '';
			
		/* Translators: If there are characters in your language that are not
		* supported by Nunito, translate this to 'off'. Do not translate
		* into your own language.
		*/
        $nunito = esc_html_x( 'off', 'Nunito font: on or off', 'seofy' );
        
        /* Translators: If there are characters in your language that are not
		* supported by Nunito, translate this to 'off'. Do not translate
		* into your own language.
		*/
		$nunito_sans = esc_html_x( 'on', 'Nunito font: on or off', 'seofy' );
		
		/* Translators: If there are characters in your language that are not
		* supported by Poppins, translate this to 'off'. Do not translate
		* into your own language.
		*/
		$poppins = esc_html_x( 'off', 'Poppins font: on or off', 'seofy' );	

		/* Translators: If there are characters in your language that are not
		* supported by Playfair Display, translate this to 'off'. Do not translate
		* into your own language.
		*/
		$playfair_display = esc_html_x( 'off', 'Playfair Display font: on or off', 'seofy' );

		/* Translators: If there are characters in your language that are not
		* supported by Open Sans, translate this to 'off'. Do not translate
		* into your own language.
		*/
		$open_sans = esc_html_x( 'off', 'Open Sans font: on or off', 'seofy' );
		
		/* Translators: If there are characters in your language that are not
		* supported by Josefin Sans, translate this to 'off'. Do not translate
		* into your own language.
		*/
		$josefin_sans = esc_html_x( 'off', 'Josefin Sans font: on or off', 'seofy' );	
		
		if ( 'off' !== $nunito || 'off' !== $nunito_sans || 'off' !== $poppins || 'off' !== $playfair_display || 'off' !== $open_sans || 'off' !== $josefin_sans) {
			$font_families = array();
				
			if ( 'off' !== $nunito ) {
				$font_families[] = 'Nunito:400,600,700';
            }

            if ( 'off' !== $nunito_sans ) {
				$font_families[] = 'Nunito Sans:400,600,700';
			}
				
			if ( 'off' !== $poppins ) {
				$font_families[] = 'Poppins:300,400,500,600,700';
			}
			if ( 'off' !== $open_sans ) {
				$font_families[] = 'Open Sans:400,600,700';
			}
				
			if ( 'off' !== $josefin_sans ) {
				$font_families[] = 'Josefin Sans:300,400,500,600,700';
			}	
				
			$query_args = array(
				'family' => urlencode( implode( '|', $font_families ) ),
				'subset' => urlencode( 'latin,latin-ext' ),
			);
				
			$fonts_url = add_query_arg( $query_args, 'https://fonts.googleapis.com/css' );
		}
		
		return esc_url_raw( $fonts_url );
	}

